import { useLocation, useNavigate } from "react-router-dom";
import { useState, useMemo } from "react";
import logo from "../assets/logo.png";

export default function Checkout() {
  const location = useLocation();
  const navigate = useNavigate();

  const cart = Array.isArray(location.state?.cart) ? location.state.cart : [];

  const [form, setForm] = useState({
    name: "",
    email: "",
    address: "",
    cardType: "visa",
    cardNumber: "",
    cvv: "",
    expiry: "",
  });

  const total = useMemo(() => {
    return cart.reduce((sum, item) => {
      const price = Number(item?.price || 0);
      const qty = Number(item?.qty || 0);
      return sum + price * qty;
    }, 0);
  }, [cart]);

  const handleChange = (e) => {
    setForm((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = () => {
    console.log("COMPRA:", {
      customer: form,
      cart,
      total,
    });

    alert("Compra realizada");
  };

  const inputStyle = {
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #ddd",
    outline: "none",
  };

  const primaryButton = {
    flex: 1,
    padding: "10px",
    backgroundColor: "#32d5d5",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  };

  const secondaryButton = {
    flex: 1,
    padding: "10px",
    backgroundColor: "#e2e8f0",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background: "#f5f7fb",
        padding: "2rem",
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: "500px",
          background: "white",
          padding: "2rem",
          borderRadius: "12px",
          boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
        }}
      >
        <div style={{ textAlign: "center", marginBottom: "1.5rem" }}>
          <img
            src={logo}
            alt="Logo"
            style={{
              width: "120px",
              marginBottom: "10px",
            }}
          />

          <h2>Checkout</h2>
        </div>

        {cart.length === 0 ? (
          <div style={{ textAlign: "center" }}>
            <p>No hay productos en el carrito.</p>

            <button
              onClick={() => navigate("/tienda")}
              style={{
                padding: "10px 16px",
                background: "#32d5d5",
                color: "white",
                border: "none",
                borderRadius: "8px",
                cursor: "pointer",
                marginTop: "10px",
              }}
            >
              Volver a la tienda
            </button>
          </div>
        ) : (
          <>
            <div style={{ marginBottom: "1rem" }}>
              {cart.map((item, index) => (
                <div
                  key={item.id || index}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    marginBottom: "6px",
                  }}
                >
                  <span>
                    {item.name || "Producto"} x {item.qty || 1}
                  </span>
                  <span>
                    $
                    {(
                      (Number(item.price) || 0) * (Number(item.qty) || 0)
                    ).toFixed(2)}
                  </span>
                </div>
              ))}
            </div>

            <h3 style={{ marginBottom: "1.5rem" }}>
              Total: ${total.toFixed(2)}
            </h3>

            <div
              style={{
                display: "flex",
                flexDirection: "column",
                gap: "10px",
              }}
            >
              <input
                name="name"
                placeholder="Nombre"
                value={form.name}
                onChange={handleChange}
                style={inputStyle}
              />

              <input
                name="email"
                placeholder="Email"
                value={form.email}
                onChange={handleChange}
                style={inputStyle}
              />

              <input
                name="address"
                placeholder="Dirección"
                value={form.address}
                onChange={handleChange}
                style={inputStyle}
              />
            </div>

            <h4 style={{ marginTop: "20px" }}>Datos de tarjeta 💳</h4>

            <div
              style={{
                display: "flex",
                flexDirection: "column",
                gap: "10px",
              }}
            >
              <select
                name="cardType"
                value={form.cardType}
                onChange={handleChange}
                style={inputStyle}
              >
                <option value="visa">Visa</option>
                <option value="mastercard">MasterCard</option>
                <option value="amex">American Express</option>
              </select>

              <input
                name="cardNumber"
                placeholder="Número de tarjeta"
                value={form.cardNumber}
                onChange={handleChange}
                style={inputStyle}
              />

              <input
                name="cvv"
                placeholder="CVV"
                value={form.cvv}
                onChange={handleChange}
                style={inputStyle}
              />

              <input
                name="expiry"
                placeholder="MM/AA"
                value={form.expiry}
                onChange={handleChange}
                style={inputStyle}
              />
            </div>

            <div
              style={{
                display: "flex",
                gap: "10px",
                marginTop: "20px",
              }}
            >
              <button onClick={handleSubmit} style={primaryButton}>
                Confirmar compra
              </button>

              <button
                onClick={() => navigate("/tienda")}
                style={secondaryButton}
              >
                Volver
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
